*** Add File: /app/drizzle-orm/src/sql/functions/window.ts
+import type { AnyColumn } from '~/column.ts';
+import { sql, type SQL, type SQLWrapper } from '../sql.ts';
+
+type WindowExpression = AnyColumn | SQL | SQL.Aliased;
+
+export interface WindowSpec {
+	partitionBy?: WindowExpression | WindowExpression[];
+	orderBy?: WindowExpression | WindowExpression[];
+	frame?: WindowFrame;
+}
+
+type BoundaryKind = 'unbounded preceding' | 'preceding' | 'current row' | 'following' | 'unbounded following';
+export interface WindowBoundary { readonly kind: BoundaryKind; readonly value?: number }
+export interface WindowFrame { readonly kind: 'rows' | 'range'; readonly from: WindowBoundary; readonly to: WindowBoundary }
+
+export const unboundedPreceding: WindowBoundary = { kind: 'unbounded preceding' };
+export const currentRow: WindowBoundary = { kind: 'current row' };
+export const unboundedFollowing: WindowBoundary = { kind: 'unbounded following' };
+
+function offsetBoundary(kind: 'preceding' | 'following', value: number): WindowBoundary {
+	if (!Number.isInteger(value) || value < 0) throw new Error(`${kind}() requires a non-negative integer; received ${value}`);
+	return { kind, value };
+}
+export const preceding = (value: number): WindowBoundary => offsetBoundary('preceding', value);
+export const following = (value: number): WindowBoundary => offsetBoundary('following', value);
+
+function boundaryPosition(boundary: WindowBoundary): number {
+	switch (boundary.kind) {
+		case 'unbounded preceding': return -Infinity;
+		case 'preceding': return -boundary.value!;
+		case 'current row': return 0;
+		case 'following': return boundary.value!;
+		case 'unbounded following': return Infinity;
+	}
+}
+function frame(kind: WindowFrame['kind'], spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	if (boundaryPosition(spec.from) > boundaryPosition(spec.to)) throw new Error('Window frame "from" boundary must not be ordered after "to"');
+	return { kind, ...spec };
+}
+export const rows = (spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame => frame('rows', spec);
+export const range = (spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame => frame('range', spec);
+
+function boundarySql(boundary: WindowBoundary): SQL {
+	return boundary.value === undefined ? sql.raw(boundary.kind) : sql`${sql.raw(String(boundary.value))} ${sql.raw(boundary.kind)}`;
+}
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const partitionBy = spec.partitionBy === undefined ? [] : (Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy]);
+	const orderBy = spec.orderBy === undefined ? [] : (Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy]);
+	const partitionSql = partitionBy.length ? sql`partition by ${sql.join(partitionBy, sql`, `)}` : undefined;
+	const orderSql = orderBy.length ? sql`order by ${sql.join(orderBy, sql`, `)}` : undefined;
+	const frameSql = spec.frame ? sql`${sql.raw(spec.frame.kind)} between ${boundarySql(spec.frame.from)} and ${boundarySql(spec.frame.to)}` : undefined;
+	return sql.join([partitionSql, orderSql, frameSql].filter((part): part is SQL => part !== undefined), sql` `);
+}
+
+class WindowFunction<T> {
+	constructor(private readonly expression: SQL<T>) {}
+	over(spec: WindowSpec | string = {}): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this.expression} over ${sql.identifier(spec)}`
+			: sql`${this.expression} over (${buildWindowSpec(spec)})`;
+	}
+}
+function windowFunction<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+function positional(name: string, value: number): SQL {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer; received ${value}`);
+	return sql.raw(String(value));
+}
+type ExpressionValue<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TValue> ? TValue : unknown;
+
+export const rowNumber = (): WindowFunction<number> => windowFunction('row_number');
+export const rank = (): WindowFunction<number> => windowFunction('rank');
+export const denseRank = (): WindowFunction<number> => windowFunction('dense_rank');
+export const ntile = (buckets: number): WindowFunction<number> => windowFunction('ntile', [positional('ntile', buckets)]);
+export const percentRank = (): WindowFunction<number> => windowFunction('percent_rank');
+export const cumeDist = (): WindowFunction<number> => windowFunction('cume_dist');
+
+export function lag<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionValue<T> | null>;
+export function lag<T extends SQLWrapper>(expression: T, offset: number, defaultValue: SQLWrapper): WindowFunction<ExpressionValue<T>>;
+export function lag<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<ExpressionValue<T> | null> {
+	return windowFunction('lag', [expression, ...(offset === undefined ? [] : [sql.raw(String(offset)]), ...(defaultValue === undefined ? [] : [defaultValue])]);
+}
+export function lead<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionValue<T> | null>;
+export function lead<T extends SQLWrapper>(expression: T, offset: number, defaultValue: SQLWrapper): WindowFunction<ExpressionValue<T>>;
+export function lead<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<ExpressionValue<T> | null> {
+	return windowFunction('lead', [expression, ...(offset === undefined ? [] : [sql.raw(String(offset)]), ...(defaultValue === undefined ? [] : [defaultValue])]);
+}
+export const firstValue = <T extends SQLWrapper>(expression: T): WindowFunction<ExpressionValue<T> | null> => windowFunction('first_value', [expression]);
+export const lastValue = <T extends SQLWrapper>(expression: T): WindowFunction<ExpressionValue<T> | null> => windowFunction('last_value', [expression]);
+export const nthValue = <T extends SQLWrapper>(expression: T, nth: number): WindowFunction<ExpressionValue<T> | null> => windowFunction('nth_value', [expression, positional('nthValue', nth)]);
+
+export const windowSum = (expression: SQLWrapper): WindowFunction<string | null> => windowFunction('sum', [expression]);
+export const windowAvg = (expression: SQLWrapper): WindowFunction<string | null> => windowFunction('avg', [expression]);
+export const windowMin = <T extends SQLWrapper>(expression: T): WindowFunction<ExpressionValue<T> | null> => windowFunction('min', [expression]);
+export const windowMax = <T extends SQLWrapper>(expression: T): WindowFunction<ExpressionValue<T> | null> => windowFunction('max', [expression]);
+export const windowCount = (expression?: SQLWrapper): WindowFunction<number> => windowFunction('count', expression === undefined ? [sql.raw('*')] : [expression]);
